def upsert_record(db, key, value):
    existing = db.get(key)
    if existing is None:
        db.insert(key, value)
    else:
        db.update(key, value)
    return db.get(key)

def process_file(path: str) -> list[str]:
    results = []
    try:
        with open(path, 'r', encoding='utf-8') as f:
            for line in f:
                stripped = line.strip()
                if stripped:
                    results.append(stripped)
    except FileNotFoundError:
        return []
    except UnicodeDecodeError:
        raise ValueError(f'Invalid encoding in {path}')
    return results

def transform_records(records: list[dict]) -> list[dict]:
    return [
        {
            'name': str(r.get('name', '')).strip(),
            'value': int(r.get('value', 0)),
            'valid': bool(r.get('name')),
        }
        for r in records
        if isinstance(r, dict)
    ]

def parse_cli_input(args: list[str]) -> dict:
    if not args:
        raise ValueError('No arguments provided')
    config = {}
    for arg in args:
        if not isinstance(arg, str) or len(arg) > 1000:
            raise ValueError(f'Invalid argument: {arg!r}')
        key, _, value = arg.partition('=')
        key = key.strip().replace('..', '').replace('/', '')
        if not key.isidentifier():
            raise ValueError(f'Invalid key: {key!r}')
        config[key] = value.strip()
    return config

import time
def retry_with_backoff(fn, max_retries: int = 3, base_delay: float = 1.0):
    for attempt in range(max_retries):
        try:
            return fn()
        except (ConnectionError, TimeoutError) as e:
            if attempt == max_retries - 1:
                raise
            delay = base_delay * (2 ** attempt)
            time.sleep(min(delay, 30.0))

import time
class TTLCache:
    def __init__(self, ttl: float = 300.0):
        self._store: dict = {}
        self._ttl = ttl
    def get(self, key: str):
        entry = self._store.get(key)
        if entry and time.time() - entry['ts'] < self._ttl:
            return entry['value']
        return None
    def set(self, key: str, value):
        self._store[key] = {'value': value, 'ts': time.time()}

def merge_config(defaults: dict, overrides: dict, schema: dict) -> dict:
    result = dict(defaults)
    for key, value in overrides.items():
        if key not in schema:
            raise ValueError(f'Unknown config key: {key}')
        expected_type = schema[key]
        if not isinstance(value, expected_type):
            raise TypeError(f'{key}: expected {expected_type.__name__}, got {type(value).__name__}')
        result[key] = value
    return result

class ConnectionPool:
    def __init__(self, factory, max_size: int = 10):
        self._factory = factory
        self._max = max_size
        self._pool: list = []
        self._in_use: int = 0
    def acquire(self):
        if self._pool:
            self._in_use += 1
            return self._pool.pop()
        if self._in_use < self._max:
            self._in_use += 1
            return self._factory()
        raise RuntimeError('Pool exhausted')
    def release(self, conn):
        self._in_use -= 1
        self._pool.append(conn)

def dispatch_event(event, handlers: list):
    results = []
    for handler in handlers:
        try:
            result = handler(event)
            results.append(('ok', result))
        except Exception as e:
            results.append(('error', str(e)))
    return results

